package io.harbor.textd.core;

import java.io.IOException;
import java.io.InputStream;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.HashMap;
import java.util.Map;
import java.util.jar.JarEntry;
import java.util.jar.JarInputStream;

final class PluginClassLoader extends ClassLoader implements AutoCloseable {
    private final Map<String, byte[]> bytecode;

    PluginClassLoader(Path pluginJar, ClassLoader parent) throws IOException {
        super(parent);
        this.bytecode = loadBytecode(pluginJar);
    }

    @Override
    protected Class<?> findClass(String name) throws ClassNotFoundException {
        byte[] bytes = bytecode.get(toEntryName(name));
        if (bytes == null) {
            throw new ClassNotFoundException(name);
        }
        return defineClass(name, bytes, 0, bytes.length);
    }

    @Override
    public void close() {
        bytecode.clear();
    }

    private static Map<String, byte[]> loadBytecode(Path pluginJar) throws IOException {
        Map<String, byte[]> classes = new HashMap<>();
        try (InputStream input = Files.newInputStream(pluginJar);
             JarInputStream jar = new JarInputStream(input)) {
            JarEntry entry;
            while ((entry = jar.getNextJarEntry()) != null) {
                if (entry.isDirectory() || !entry.getName().endsWith(".class")) {
                    continue;
                }
                classes.put(entry.getName(), jar.readAllBytes());
            }
        }
        return classes;
    }

    private static String toEntryName(String className) {
        return className.replace('.', '/') + ".class";
    }
}

