package io.harbor.textd.cli;

import io.harbor.textd.core.OutputFormat;
import io.harbor.textd.core.ProcessingResult;
import io.harbor.textd.core.TextDaemon;

import java.nio.file.Path;
import java.util.List;

public final class SessionReclaimProbeRunner {
    private static final String SAMPLE = "alpha beta gamma";

    private SessionReclaimProbeRunner() {
    }

    public static void main(String[] args) throws Exception {
        Path pluginJar = Path.of(args[0]);
        int revision = args.length > 1 ? Integer.parseInt(args[1]) : 4;
        long lingerMillis = args.length > 2 ? Long.parseLong(args[2]) : 5_000L;

        runSession(pluginJar, revision);
        drainGc();

        System.out.println("probe-ready pid=" + ProcessHandle.current().pid());
        System.out.flush();
        Thread.sleep(lingerMillis);
    }

    private static void runSession(Path pluginJar, int revision) throws Exception {
        TextDaemon daemon = new TextDaemon(pluginJar, 4);
        try {
            for (int current = 1; current <= revision; current++) {
                daemon.reload(current);
                List<ProcessingResult> results = daemon.processBatch(List.of(SAMPLE, SAMPLE, SAMPLE, SAMPLE));
                assertOutputs(current, results);
            }

            if (!daemon.isBalanced()) {
                throw new IllegalStateException("Runtime remained unbalanced before close");
            }

            daemon.close();
            if (!daemon.isBalanced()) {
                throw new IllegalStateException("Runtime remained unbalanced after close");
            }
        } catch (Exception exception) {
            try {
                daemon.close();
            } catch (Exception closeException) {
                exception.addSuppressed(closeException);
            }
            throw exception;
        }
    }

    private static void drainGc() throws InterruptedException {
        for (int i = 0; i < 5; i++) {
            System.gc();
            Thread.sleep(100);
        }
    }

    private static void assertOutputs(long revision, List<ProcessingResult> results) {
        String expected = OutputFormat.expectedFor(revision, SAMPLE);
        for (ProcessingResult result : results) {
            if (!expected.equals(result.output())) {
                throw new IllegalStateException("Unexpected output at revision " + revision + ": " + result.output());
            }
        }
    }
}
